const today = new Date();
const formatDate = (date) => date.toISOString().split('T')[0];
const getDateDaysAgo = (days) => { const d = new Date(today); d.setDate(d.getDate() - days); return formatDate(d); };

// ========================================
// SPRINT CALCULATION
// Sprints start on 1st and 3rd Monday of each month
// ========================================
const getNthMondayOfMonth = (year, month, n) => {
  const firstDay = new Date(year, month, 1);
  const dayOfWeek = firstDay.getDay();
  const firstMonday = dayOfWeek <= 1 ? 1 + (1 - dayOfWeek) : 1 + (8 - dayOfWeek);
  const nthMonday = firstMonday + (n - 1) * 7;
  return new Date(year, month, nthMonday);
};

const getSprintDates = (referenceDate) => {
  const year = referenceDate.getFullYear();
  const month = referenceDate.getMonth();
  const firstMonday = getNthMondayOfMonth(year, month, 1);
  const thirdMonday = getNthMondayOfMonth(year, month, 3);
  const nextMonth = month === 11 ? 0 : month + 1;
  const nextYear = month === 11 ? year + 1 : year;
  const nextFirstMonday = getNthMondayOfMonth(nextYear, nextMonth, 1);

  let currentSprint, previousSprint;

  if (referenceDate >= thirdMonday) {
    currentSprint = {
      name: `Sprint 2`, number: 2, startDate: thirdMonday,
      endDate: new Date(nextFirstMonday.getTime() - 1),
      month: referenceDate.toLocaleString('en-US', { month: 'short' }), year: year
    };
    previousSprint = {
      name: `Sprint 1`, number: 1, startDate: firstMonday,
      endDate: new Date(thirdMonday.getTime() - 1),
      month: referenceDate.toLocaleString('en-US', { month: 'short' }), year: year
    };
  } else if (referenceDate >= firstMonday) {
    currentSprint = {
      name: `Sprint 1`, number: 1, startDate: firstMonday,
      endDate: new Date(thirdMonday.getTime() - 1),
      month: referenceDate.toLocaleString('en-US', { month: 'short' }), year: year
    };
    const prevMonth = month === 0 ? 11 : month - 1;
    const prevYear = month === 0 ? year - 1 : year;
    const prevThirdMonday = getNthMondayOfMonth(prevYear, prevMonth, 3);
    previousSprint = {
      name: `Sprint 2`, number: 2, startDate: prevThirdMonday,
      endDate: new Date(firstMonday.getTime() - 1),
      month: new Date(prevYear, prevMonth).toLocaleString('en-US', { month: 'short' }), year: prevYear
    };
  } else {
    const prevMonth = month === 0 ? 11 : month - 1;
    const prevYear = month === 0 ? year - 1 : year;
    const prevThirdMonday = getNthMondayOfMonth(prevYear, prevMonth, 3);
    currentSprint = {
      name: `Sprint 2`, number: 2, startDate: prevThirdMonday,
      endDate: new Date(firstMonday.getTime() - 1),
      month: new Date(prevYear, prevMonth).toLocaleString('en-US', { month: 'short' }), year: prevYear
    };
    const prevFirstMonday = getNthMondayOfMonth(prevYear, prevMonth, 1);
    previousSprint = {
      name: `Sprint 1`, number: 1, startDate: prevFirstMonday,
      endDate: new Date(prevThirdMonday.getTime() - 1),
      month: new Date(prevYear, prevMonth).toLocaleString('en-US', { month: 'short' }), year: prevYear
    };
  }

  const countWorkingDays = (start, end) => {
    let count = 0;
    const current = new Date(start);
    while (current <= end) {
      const day = current.getDay();
      if (day !== 0 && day !== 6) count++;
      current.setDate(current.getDate() + 1);
    }
    return count;
  };

  currentSprint.workingDays = countWorkingDays(currentSprint.startDate, currentSprint.endDate);
  currentSprint.totalHours = currentSprint.workingDays * HOURS_PER_DAY;
  const todayMidnight = new Date(referenceDate);
  todayMidnight.setHours(23, 59, 59, 999);
  currentSprint.elapsedWorkingDays = countWorkingDays(currentSprint.startDate, todayMidnight);
  currentSprint.elapsedHours = currentSprint.elapsedWorkingDays * HOURS_PER_DAY;
  currentSprint.remainingWorkingDays = currentSprint.workingDays - currentSprint.elapsedWorkingDays;
  currentSprint.remainingHours = currentSprint.remainingWorkingDays * HOURS_PER_DAY;
  currentSprint.sprintDay = currentSprint.elapsedWorkingDays;
  currentSprint.label = `${currentSprint.month} ${currentSprint.name}`;
  currentSprint.dateRange = `${formatDate(currentSprint.startDate)} to ${formatDate(currentSprint.endDate)}`;

  previousSprint.workingDays = countWorkingDays(previousSprint.startDate, previousSprint.endDate);
  previousSprint.totalHours = previousSprint.workingDays * HOURS_PER_DAY;
  previousSprint.elapsedWorkingDays = previousSprint.workingDays;
  previousSprint.elapsedHours = previousSprint.totalHours;
  previousSprint.remainingWorkingDays = 0;
  previousSprint.remainingHours = 0;
  previousSprint.sprintDay = previousSprint.workingDays;
  previousSprint.label = `${previousSprint.month} ${previousSprint.name}`;
  previousSprint.dateRange = `${formatDate(previousSprint.startDate)} to ${formatDate(previousSprint.endDate)}`;

  return { current: currentSprint, previous: previousSprint };
};

const sprints = getSprintDates(today);
console.log(`🏃 Current Sprint: ${sprints.current.label}`);
console.log(`   Day ${sprints.current.sprintDay} of ${sprints.current.workingDays}`);

const periods = {
  '7days': { start: getDateDaysAgo(7), end: formatDate(today), label: 'Last 7 Days' },
  '15days': { start: getDateDaysAgo(15), end: formatDate(today), label: 'Last 15 Days' },
  '30days': { start: getDateDaysAgo(30), end: formatDate(today), label: 'Last 30 Days' }
};

return [{
  json: {
    boardComponents: BOARD_COMPONENTS,
    projectKey: PROJECT_KEY,
    hoursPerDay: HOURS_PER_DAY,
    teamMembers,
    periods,
    sprints: {
      current: { ...sprints.current, startDate: formatDate(sprints.current.startDate), endDate: formatDate(sprints.current.endDate) },
      previous: { ...sprints.previous, startDate: formatDate(sprints.previous.startDate), endDate: formatDate(sprints.previous.endDate) }
    },
    today: formatDate(today),
    timestamp: today.toISOString()
  }
}];

// Process JIRA data and aggregate per team member
// SUPPORTS MULTIPLE COMPONENTS DYNAMICALLY

const configData = $('⚙️ Setup Config').first().json;
const teamMembers = configData.teamMembers;
const BOARD_COMPONENTS = configData.boardComponents; // Array of components
const PROJECT_KEY = configData.projectKey;
const sprints = configData.sprints;

const rawIssues = $('📥 JIRA - All Data (30 Days)').all().map(i => i.json);
console.log(`📊 Total issues fetched: ${rawIssues.length}`);

// Filter by ANY of the configured components
const allIssues = rawIssues.filter(issue => {
  const components = issue.fields?.components || [];
  return components.some(comp => BOARD_COMPONENTS.includes(comp.name));
});
console.log(`📊 Issues with components [${BOARD_COMPONENTS.join(', ')}]: ${allIssues.length}`);

// Date cutoffs for periods
const now = new Date();
const cutoff7d = new Date(now); cutoff7d.setDate(now.getDate() - 7);
const cutoff15d = new Date(now); cutoff15d.setDate(now.getDate() - 15);
const cutoff30d = new Date(now); cutoff30d.setDate(now.getDate() - 30);

// Sprint date parsing
const currentSprintStart = new Date(sprints.current.startDate);
const currentSprintEnd = new Date(sprints.current.endDate);
currentSprintEnd.setHours(23, 59, 59, 999);
const previousSprintStart = new Date(sprints.previous.startDate);
const previousSprintEnd = new Date(sprints.previous.endDate);
previousSprintEnd.setHours(23, 59, 59, 999);

const filterByPeriod = (issues, cutoffDate) => {
  return issues.filter(issue => new Date(issue.fields?.updated || issue.fields?.created) >= cutoffDate);
};

const filterBySprint = (issues, startDate, endDate) => {
  return issues.filter(issue => {
    const createdDate = new Date(issue.fields?.created);
    return createdDate >= startDate && createdDate <= endDate;
  });
};

const issues7d = filterByPeriod(allIssues, cutoff7d);
const issues15d = filterByPeriod(allIssues, cutoff15d);
const issues30d = allIssues;
const issuesCurrentSprint = filterBySprint(allIssues, currentSprintStart, currentSprintEnd);
const issuesPreviousSprint = filterBySprint(allIssues, previousSprintStart, previousSprintEnd);

console.log(`🏃 Current Sprint issues: ${issuesCurrentSprint.length}`);
console.log(`🏃 Previous Sprint issues: ${issuesPreviousSprint.length}`);

// Board info - DYNAMIC based on components
const boardInfo = {
  name: BOARD_COMPONENTS.join(' & '), // e.g., "Bot Engine & RE Platform 2.0"
  project: PROJECT_KEY,
  components: BOARD_COMPONENTS
};

// Status mapping
const statusMapping = {
  'To Do': 'toDo', 'TO DO': 'toDo', 'Open': 'toDo', 'Backlog': 'toDo', 'New': 'toDo',
  'In Progress': 'inProgress', 'IN PROGRESS': 'inProgress', 'In Review': 'inProgress',
  'Code Review': 'inProgress', 'In Development': 'inProgress', 'Development': 'inProgress',
  'UAT': 'uat', 'QA': 'uat', 'Testing': 'uat', 'Ready for UAT': 'uat',
  'Done': 'done', 'DONE': 'done', 'Closed': 'done', 'Resolved': 'done', 'Complete': 'done', 'Completed': 'done'
};
const getNormalizedStatus = (status) => statusMapping[status] || 'toDo';

// Helper: Check if member matches assignee
const isMemberAssignee = (issue, memberEmail) => {
  const assignee = issue.fields?.assignee;
  if (!assignee) return false;
  const emailLower = memberEmail.toLowerCase();
  const emailPrefix = emailLower.split('@')[0];
  const assigneeEmail = (assignee.emailAddress || '').toLowerCase();
  if (assigneeEmail === emailLower || assigneeEmail.includes(emailPrefix)) return true;
  const displayName = (assignee.displayName || '').toLowerCase();
  const nameParts = emailPrefix.replace(/[0-9]/g, '').replace(/\./g, ' ').split(' ').filter(p => p.length > 2);
  if (nameParts.length > 0 && nameParts.every(part => displayName.includes(part))) return true;
  return false;
};

// Get member's issues with time data
const getMemberIssuesWithTime = (issues, memberEmail) => {
  return issues.filter(issue => isMemberAssignee(issue, memberEmail)).map(issue => {
    const timeSpentSeconds = issue.fields?.timespent || 0;
    const timeSpentHours = timeSpentSeconds / 3600;
    return {
      key: issue.key,
      summary: issue.fields?.summary || '',
      status: getNormalizedStatus(issue.fields?.status?.name || 'To Do'),
      statusName: issue.fields?.status?.name || 'To Do',
      timeSpentSeconds,
      timeSpentHours: Math.round(timeSpentHours * 10) / 10,
      priority: issue.fields?.priority?.name || 'Medium',
      created: issue.fields?.created
    };
  });
};

// Calculate metrics for a member
const getMemberMetrics = (issues, memberEmail) => {
  const memberIssues = getMemberIssuesWithTime(issues, memberEmail);
  const counts = { total: memberIssues.length, done: 0, inProgress: 0, uat: 0, toDo: 0 };
  let totalHoursLogged = 0;

  memberIssues.forEach(issue => {
    counts[issue.status]++;
    totalHoursLogged += issue.timeSpentHours;
  });

  const topIssues = memberIssues
    .filter(i => i.timeSpentHours > 0)
    .sort((a, b) => b.timeSpentHours - a.timeSpentHours)
    .slice(0, 4)
    .map(i => ({ key: i.key, summary: i.summary, status: i.status, statusName: i.statusName, hours: i.timeSpentHours }));

  return { ...counts, hoursLogged: Math.round(totalHoursLogged * 10) / 10, topIssues };
};

// Calculate SPRINT metrics for a member
const getMemberSprintMetrics = (issues, memberEmail, sprintInfo) => {
  const memberIssues = getMemberIssuesWithTime(issues, memberEmail);
  const counts = { total: memberIssues.length, done: 0, inProgress: 0, uat: 0, toDo: 0 };
  let totalHoursLogged = 0;

  memberIssues.forEach(issue => {
    counts[issue.status]++;
    totalHoursLogged += issue.timeSpentHours;
  });

  const topIssues = memberIssues
    .filter(i => i.timeSpentHours > 0)
    .sort((a, b) => b.timeSpentHours - a.timeSpentHours)
    .slice(0, 4)
    .map(i => ({ key: i.key, summary: i.summary, status: i.status, statusName: i.statusName, hours: i.timeSpentHours }));

  const allSprintIssues = memberIssues.map(i => ({
    key: i.key, summary: i.summary, status: i.status, statusName: i.statusName, hours: i.timeSpentHours
  }));

  return {
    ...counts,
    hoursLogged: Math.round(totalHoursLogged * 10) / 10,
    totalHours: sprintInfo.totalHours,
    workingDays: sprintInfo.workingDays,
    topIssues,
    allIssues: allSprintIssues
  };
};

// Calculate team summary
const calculateTeamSummary = (issues) => {
  const summary = { total: issues.length, done: 0, inProgress: 0, uat: 0, toDo: 0, totalHoursLogged: 0 };
  issues.forEach(issue => {
    summary[getNormalizedStatus(issue.fields?.status?.name || 'To Do')]++;
    summary.totalHoursLogged += (issue.fields?.timespent || 0) / 3600;
  });
  summary.totalHoursLogged = Math.round(summary.totalHoursLogged * 10) / 10;
  return summary;
};

const workingHours = { '7days': 40, '15days': 88, '30days': 176 };

const outputData = {
  lastUpdated: new Date().toISOString(),
  generatedAt: configData.timestamp,
  boardInfo,
  workingHours,
  sprints: configData.sprints,
  periods: {
    '7days': { label: 'Last 7 Days', startDate: configData.periods['7days'].start, endDate: configData.periods['7days'].end },
    '15days': { label: 'Last 15 Days', startDate: configData.periods['15days'].start, endDate: configData.periods['15days'].end },
    '30days': { label: 'Last 30 Days', startDate: configData.periods['30days'].start, endDate: configData.periods['30days'].end }
  },
  teamSummary: {
    '7days': calculateTeamSummary(issues7d),
    '15days': calculateTeamSummary(issues15d),
    '30days': calculateTeamSummary(issues30d),
    'currentSprint': calculateTeamSummary(issuesCurrentSprint),
    'previousSprint': calculateTeamSummary(issuesPreviousSprint)
  },
  members: teamMembers.map(member => ({
    name: member.name,
    email: member.email,
    avatar: member.avatar,
    metrics: {
      '7days': getMemberMetrics(issues7d, member.email),
      '15days': getMemberMetrics(issues15d, member.email),
      '30days': getMemberMetrics(issues30d, member.email)
    },
    sprintMetrics: {
      current: getMemberSprintMetrics(issuesCurrentSprint, member.email, sprints.current),
      previous: getMemberSprintMetrics(issuesPreviousSprint, member.email, sprints.previous)
    }
  }))
};

console.log('✅ Processing complete!');
console.log(`📋 Boards: ${outputData.boardInfo.name}`);
console.log(`👥 Members: ${outputData.members.length}`);
console.log(`📊 Total 7d tasks: ${outputData.teamSummary['7days'].total}`);

return [{ json: outputData }];

// Format JSON for output
const data = $input.first().json;

console.log('=== Performance Dashboard Data Generated ===');
console.log(`Last Updated: ${data.lastUpdated}`);
console.log(`Boards: ${data.boardInfo.name}`);
console.log(`Team Members: ${data.members.length}`);
console.log('');
console.log('Team Summary (7 days):');
console.log(`  Total: ${data.teamSummary['7days'].total}`);
console.log(`  Done: ${data.teamSummary['7days'].done}`);
console.log(`  In Progress: ${data.teamSummary['7days'].inProgress}`);
console.log(`  UAT: ${data.teamSummary['7days'].uat}`);
console.log(`  To Do: ${data.teamSummary['7days'].toDo}`);

return [{
  json: {
    performanceData: data,
    jsonString: JSON.stringify(data, null, 2)
  }
}];

// Success log
const data = $input.first().json;
console.log('✅ Performance Dashboard data generated successfully!');
console.log(`📅 Generated at: ${new Date().toISOString()}`);
console.log(`👥 Team Members: ${data.performanceData?.members?.length || 0}`);
return [{ json: { status: 'success', message: 'Dashboard data generated', timestamp: new Date().toISOString() } }];
